### Create Supabase Storage Bucket with Conflict Handling (TypeScript)

Source: https://github.com/supabase/supabase-js/blob/master/packages/core/storage-js/README.md

This asynchronous function attempts to create a new analytics bucket. It includes error handling to specifically check for a '409 Conflict' status code, which indicates that the bucket already exists. For other errors, it logs the message and returns a failure status.

```typescript
async function ensureAnalyticsBucket(bucketName: string) {
  // Try to create the bucket
  const { data, error } = await analytics.createBucket(bucketName)

  if (error) {
    // Check if bucket already exists (conflict error)
    if (error.statusCode === '409') {
      console.log(`Bucket '${bucketName}' already exists`)
      return { success: true, created: false }
    }

    // Other error occurred
    console.error('Failed to create bucket:', error.message)
    return { success: false, error }
  }

  console.log(`Created new bucket: '${bucketName}'`)
  return { success: true, created: true, data }
}
```

